1	import * as THREE from 'three';
2	import { Sky } from 'three/addons/objects/Sky.js';
3	import { liveTokenReader, type ElementCategoryToken, type ViewportPaintBundle } from './materials';
4	
5	export const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';
6	
7	export function categoryColorOr(
8	  bundle: ViewportPaintBundle | null,
9	  cat: ElementCategoryToken,
10	): string {
11	  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
12	}
13	
14	export function readToken(name: string, fallback: string): string {
15	  const v = liveTokenReader().read(name);
16	  return v && v.trim().length > 0 ? v : fallback;
17	}
18	
19	/** Resolve a CSS color token to an rgb() string that Three.js can parse.
20	 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
21	 * Three.js does not support — routing through a DOM element forces the
22	 * browser to resolve it to "rgb(r, g, b)". */
23	export function readColorToken(name: string, fallback: string): string {
24	  if (typeof document === 'undefined') return fallback;
25	  try {
26	    const el = document.createElement('div');
27	    el.style.display = 'none';
28	    el.style.color = `var(${name}, ${fallback})`;
29	    document.body.appendChild(el);
30	    const resolved = getComputedStyle(el).color;
31	    document.body.removeChild(el);
32	    return resolved || fallback;
33	  } catch {
34	    return fallback;
35	  }
36	}
