38	export function sunPositionFromAzEl(
39	  azimuthDeg: number,
40	  elevationDeg: number,
41	  radiusM = 80,
42	): THREE.Vector3 {
43	  const az = THREE.MathUtils.degToRad(azimuthDeg);
44	  const el = THREE.MathUtils.degToRad(elevationDeg);
45	  return new THREE.Vector3(
46	    radiusM * Math.cos(el) * Math.sin(az),
47	    radiusM * Math.sin(el),
48	    radiusM * Math.cos(el) * Math.cos(az),
49	  );
50	}
51	
52	export function buildSkyEnvMap(
53	  renderer: THREE.WebGLRenderer,
54	  azimuthDeg: number,
55	  elevationDeg: number,
56	): THREE.Texture {
57	  const sky = new Sky();
58	  sky.scale.setScalar(450000);
59	  const u = sky.material.uniforms;
60	  u['turbidity'].value = 3;
61	  u['rayleigh'].value = 0.5;
62	  u['mieCoefficient'].value = 0.005;
63	  u['mieDirectionalG'].value = 0.8;
64	  const phi = THREE.MathUtils.degToRad(90 - elevationDeg);
65	  const theta = THREE.MathUtils.degToRad(azimuthDeg);
66	  u['sunPosition'].value.setFromSphericalCoords(1, phi, theta);
67	  const pmrem = new THREE.PMREMGenerator(renderer);
68	  pmrem.compileEquirectangularShader();
69	  const tempScene = new THREE.Scene();
70	  tempScene.add(sky);
71	  const envTexture = pmrem.fromScene(tempScene).texture;
72	  pmrem.dispose();
73	  (sky.material as THREE.ShaderMaterial).dispose();
74	  sky.geometry.dispose();
75	  return envTexture;
76	}
77	
78	export function addEdges(mesh: THREE.Mesh, thresholdAngleDeg = 15): THREE.LineSegments {
79	  const color = readToken('--color-foreground', '#1a1a1a');
80	  const edges = new THREE.EdgesGeometry(mesh.geometry, thresholdAngleDeg);
81	  const mat = new THREE.LineBasicMaterial({ color, linewidth: 1 });
82	  const lines = new THREE.LineSegments(edges, mat);
83	  lines.renderOrder = 1;
84	  lines.castShadow = false;
85	  lines.receiveShadow = false;
86	  mesh.add(lines);
87	  return lines;
88	}
