1	/**
2	 * SKB-23 — per-phase preview rendering filter.
3	 *
4	 * Pure helper. Given the active phase filter (from the Zustand store) and
5	 * an element, decides whether the element should render. The Three.js
6	 * scene-builder + plan projector both consult `isElementVisibleUnderPhaseFilter`
7	 * before adding geometry.
8	 */
9	
10	export type PhaseFilter = {
11	  phases: string[];
12	  includeUntagged: boolean;
13	} | null;
14	
15	/**
16	 * Returns true when the element should render given the active phase
17	 * filter. With `filter === null` (no filter active), every element
18	 * renders — this is the default state.
19	 */
20	export function isElementVisibleUnderPhaseFilter(
21	  filter: PhaseFilter,
22	  element: { phaseId?: string | null } | null | undefined,
23	): boolean {
24	  if (!filter) return true;
25	  if (!element) return false;
26	  const phase = element.phaseId ?? null;
27	  if (phase === null) return filter.includeUntagged;
28	  return filter.phases.includes(phase);
29	}
