import * as THREE from 'three';
import type { Element } from '@bim-ai/core';
import { materialBaseColor } from './materials';
import { readToken } from './sceneHelpers';

export type MassElem = Extract<Element, { kind: 'mass' }>;
export type LevelElem = Extract<Element, { kind: 'level' }>;

/**
 * SKB-02 — translucent volumetric mesh for a `mass` element.
 *
 * The footprint polygon is extruded vertically by `heightMm` and placed
 * at the host level's elevation. The result is rotated by `rotationDeg`
 * around the vertical (Y) axis at the polygon centroid so masses can
 * sit at non-axis-aligned angles before walls are authored.
 *
 * Returns the translucent mesh and a separate outline `LineSegments`
 * (also attached as a child of the mesh) so callers can manipulate the
 * outline independently if needed.
 */
export function buildMassMesh(
  mass: MassElem,
  level: LevelElem,
): { mesh: THREE.Mesh; outline: THREE.LineSegments } {
  const fp = mass.footprintMm.length >= 3 ? mass.footprintMm : DEFAULT_FOOTPRINT;
  const heightM = Math.max(mass.heightMm / 1000, 1e-3);

  const shape = new THREE.Shape(fp.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000)));
  const geom = new THREE.ExtrudeGeometry(shape, { depth: heightM, bevelEnabled: false });
  geom.rotateX(-Math.PI / 2);

  const baseColor = materialBaseColor(mass.materialKey ?? null);
  const mat = new THREE.MeshStandardMaterial({
    color: new THREE.Color(baseColor),
    roughness: 0.85,
    metalness: 0,
    transparent: true,
    opacity: 0.35,
    side: THREE.DoubleSide,
    depthWrite: false,
  });

  const mesh = new THREE.Mesh(geom, mat);
  mesh.position.set(0, level.elevationMm / 1000, 0);

  if (Math.abs(mass.rotationDeg ?? 0) > 1e-9) {
    const centroid = polygonCentroidM(fp);
    mesh.position.x += centroid.xM;
    mesh.position.z += centroid.zM;
    mesh.rotation.y = THREE.MathUtils.degToRad(mass.rotationDeg);
    mesh.translateX(-centroid.xM);
    mesh.translateZ(-centroid.zM);
  }

  mesh.castShadow = false;
  mesh.receiveShadow = false;
  mesh.userData.bimPickId = mass.id;

  const outlineColor = readToken('--color-foreground', '#1a1a1a');
  const edges = new THREE.EdgesGeometry(geom, 1);
  const outline = new THREE.LineSegments(
    edges,
    new THREE.LineBasicMaterial({ color: outlineColor, linewidth: 1 }),
  );
  outline.renderOrder = 1;
  outline.castShadow = false;
  outline.receiveShadow = false;
  mesh.add(outline);

  return { mesh, outline };
}

const DEFAULT_FOOTPRINT = [
  { xMm: 0, yMm: 0 },
  { xMm: 4000, yMm: 0 },
  { xMm: 4000, yMm: 4000 },
  { xMm: 0, yMm: 4000 },
];

function polygonCentroidM(pts: { xMm: number; yMm: number }[]): { xM: number; zM: number } {
  let sx = 0;
  let sy = 0;
  for (const p of pts) {
    sx += p.xMm;
    sy += p.yMm;
  }
  const n = Math.max(pts.length, 1);
  return { xM: sx / n / 1000, zM: sy / n / 1000 };
}

import { describe, expect, it } from 'vitest';
import * as THREE from 'three';
import { buildMassMesh, type LevelElem, type MassElem } from './meshBuilders.mass';

const LEVEL: LevelElem = {
  kind: 'level',
  id: 'lvl-1',
  name: 'Ground',
  elevationMm: 0,
};

describe('buildMassMesh', () => {
  it('builds an extruded translucent volume from an axis-aligned 4-vertex footprint', () => {
    const mass: MassElem = {
      kind: 'mass',
      id: 'm1',
      name: 'Box',
      levelId: 'lvl-1',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 5000, yMm: 0 },
        { xMm: 5000, yMm: 8000 },
        { xMm: 0, yMm: 8000 },
      ],
      heightMm: 6000,
      rotationDeg: 0,
      materialKey: null,
      phaseId: 'massing',
      pinned: false,
    };

    const { mesh, outline } = buildMassMesh(mass, LEVEL);

    expect(mesh).toBeInstanceOf(THREE.Mesh);
    expect(outline).toBeInstanceOf(THREE.LineSegments);
    const mat = mesh.material as THREE.MeshStandardMaterial;
    expect(mat.transparent).toBe(true);
    expect(mat.opacity).toBeCloseTo(0.35, 6);
    expect(mat.side).toBe(THREE.DoubleSide);
    expect(mesh.userData.bimPickId).toBe('m1');

    mesh.geometry.computeBoundingBox();
    const bb = mesh.geometry.boundingBox!;
    expect(bb.min.x).toBeCloseTo(0, 6);
    expect(bb.max.x).toBeCloseTo(5, 6);
    expect(bb.min.y).toBeCloseTo(0, 6);
    expect(bb.max.y).toBeCloseTo(6, 6);
    expect(bb.min.z).toBeCloseTo(-8, 6);
    expect(bb.max.z).toBeCloseTo(0, 6);
  });

  it('builds extra geometry for an L-shaped (5+ vertex) footprint', () => {
    const mass: MassElem = {
      kind: 'mass',
      id: 'm2',
      name: 'L',
      levelId: 'lvl-1',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 6000, yMm: 0 },
        { xMm: 6000, yMm: 3000 },
        { xMm: 3000, yMm: 3000 },
        { xMm: 3000, yMm: 6000 },
        { xMm: 0, yMm: 6000 },
      ],
      heightMm: 3000,
      rotationDeg: 0,
      materialKey: null,
      phaseId: 'massing',
      pinned: false,
    };

    const rect: MassElem = {
      ...mass,
      id: 'm-rect',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 5000, yMm: 0 },
        { xMm: 5000, yMm: 8000 },
        { xMm: 0, yMm: 8000 },
      ],
    };

    const { mesh: lMesh } = buildMassMesh(mass, LEVEL);
    const { mesh: rMesh } = buildMassMesh(rect, LEVEL);

    const lCount = lMesh.geometry.getAttribute('position').count;
    const rCount = rMesh.geometry.getAttribute('position').count;
    expect(lCount).toBeGreaterThan(8);
    expect(lCount).toBeGreaterThan(rCount);
  });

  it('positions the mesh at the host level elevation', () => {
    const mass: MassElem = {
      kind: 'mass',
      id: 'm3',
      name: 'Upper',
      levelId: 'lvl-2',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 1000, yMm: 0 },
        { xMm: 1000, yMm: 1000 },
        { xMm: 0, yMm: 1000 },
      ],
      heightMm: 3000,
      rotationDeg: 0,
      materialKey: null,
      phaseId: 'massing',
      pinned: false,
    };
    const lvl: LevelElem = { kind: 'level', id: 'lvl-2', name: 'L2', elevationMm: 3500 };
    const { mesh } = buildMassMesh(mass, lvl);
    expect(mesh.position.y).toBeCloseTo(3.5, 6);
  });

  it('applies rotationDeg around the polygon centroid', () => {
    const mass: MassElem = {
      kind: 'mass',
      id: 'm4',
      name: 'Rotated',
      levelId: 'lvl-1',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 2000, yMm: 0 },
        { xMm: 2000, yMm: 2000 },
        { xMm: 0, yMm: 2000 },
      ],
      heightMm: 3000,
      rotationDeg: 45,
      materialKey: null,
      phaseId: 'massing',
      pinned: false,
    };
    const { mesh } = buildMassMesh(mass, LEVEL);
    expect(mesh.rotation.y).toBeCloseTo(THREE.MathUtils.degToRad(45), 6);
  });

  it('attaches the outline as a child of the mesh', () => {
    const mass: MassElem = {
      kind: 'mass',
      id: 'm5',
      name: 'Box',
      levelId: 'lvl-1',
      footprintMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 1000, yMm: 0 },
        { xMm: 1000, yMm: 1000 },
        { xMm: 0, yMm: 1000 },
      ],
      heightMm: 2500,
      rotationDeg: 0,
      materialKey: null,
      phaseId: 'massing',
      pinned: false,
    };
    const { mesh, outline } = buildMassMesh(mass, LEVEL);
    expect(mesh.children).toContain(outline);
  });
});
